public class UncheckedCast {
    @SuppressWarnings("unchecked")
    static <T> T firstElement(Object[] arr) {
        return (T) arr[0];   // unchecked cast
    }
    public static void main(String[] args) {
        Object[] arr = {"hello", 42};
        Integer n = firstElement(arr);  // ClassCastException at runtime
        System.out.println(n);
    }
}
